   426→            }
   427→        }
   428→        catch (const std::exception &ex)
   429→        {
   430→            _consumedErr->inc();
   431→            LOG_ERROR("[EventBus] Callback threw: {}", ex.what());
   432→        }
   433→    }
   434→
   435→    consumer->close();
   436→    LOG_INFO("[EventBus] Consumer loop stopped for {}", topic);
   437→}
