   191→namespace {
   192→
   193→std::unique_ptr<RdKafka::Conf> buildKafkaConf(const KafkaConfig& cfg,
   194→                                              const std::string&  confType)
   195→{
   196→    std::string errstr;
   197→    std::unique_ptr<RdKafka::Conf> conf{RdKafka::Conf::create(confType.c_str())};
   198→
   199→    auto set = [&](const std::string& key, const std::string& val) {
   200→        if (val.empty()) return;
   201→        if (conf->set(key, val, errstr) != RdKafka::Conf::CONF_OK) {
   202→            throw std::runtime_error("Kafka config error [" + key + "]: " + errstr);
   203→        }
   204→    };
   205→
   206→    set("bootstrap.servers", cfg.brokers);
   207→    set("group.id", cfg.groupId);
   208→    set("enable.auto.commit", "true");
   209→
   210→    // Optional security (HIPAA)
   211→    set("security.protocol", cfg.securityProtocol);
   212→    set("sasl.mechanisms", cfg.saslMechanisms);
   213→    set("sasl.username", cfg.saslUsername);
   214→    set("sasl.password", cfg.saslPassword);
   215→
   216→    return conf;
   217→}
