   221→StreamProcessor::StreamProcessor(KafkaConfig config, std::size_t parallelism)
   222→    : cfg_{std::move(config)}
   223→    , maxInFlight_{parallelism == 0 ? 1 : parallelism}
   224→{
   225→    std::string errstr;
   226→
   227→    auto consumerConf   = buildKafkaConf(cfg_, "consumer");
   228→    consumerConf->set("auto.offset.reset", "latest", errstr);
   229→    consumer_           = std::unique_ptr<RdKafka::KafkaConsumer>(
   230→        RdKafka::KafkaConsumer::create(consumerConf.get(), errstr));
   231→    if (!consumer_) throw std::runtime_error("Failed to create KafkaConsumer: " + errstr);
   232→
   233→    auto producerConf   = buildKafkaConf(cfg_, "producer");
   234→    producer_           = std::unique_ptr<RdKafka::Producer>(
   235→        RdKafka::Producer::create(producerConf.get(), errstr));
   236→    if (!producer_) throw std::runtime_error("Failed to create KafkaProducer: " + errstr);
   237→}
