   270→void StreamProcessor::registerStrategy(std::unique_ptr<TransformationStrategy> strat)
   271→{
   272→    std::lock_guard<std::mutex> lk{stratMtx_};
   273→    strategies_.emplace_back(std::move(strat));
   274→}
