    42→namespace ci360::services {
    43→
    44→/* ---------- Utility Types ------------------------------------------------ */
    45→
    46→enum class Severity : uint8_t
    47→{
    48→    Info,
    49→    Warning,
    50→    Critical
    51→};
    52→
    53→/* Fully-qualified alert message routed to nurse stations, etc. */
    54→struct AlertMessage
    55→{
    56→    std::string patient_id;
    57→    std::string rule_id;          // Identifier of the rule that triggered
    58→    Severity    severity;
    59→    std::string description;
    60→    std::string timestamp_utc;    // ISO-8601
    61→};
    62→
    63→/* Callback signature for clients that wish to observe alerts. */
    64→using AlertCallback = std::function<void(const AlertMessage&)>;
    65→
    66→/* ---------- Alerting Service -------------------------------------------- */
    67→
    68→class AlertingService final
    69→{
    70→public:
    71→    explicit AlertingService(const nlohmann::json& config);
    72→    ~AlertingService();
    73→
    74→    AlertingService(const AlertingService&)            = delete;
    75→    AlertingService& operator=(const AlertingService&) = delete;
    76→
    77→    void start();
    78→    void stop();
    79→
    80→    /* Register an in-process observer. Thread-safe. */
    81→    void registerObserver(AlertCallback cb);
    82→
    83→private:
    84→    /* -------------------- Rule Engine Internals ------------------------- */
    85→
    86→    struct ThresholdRule
    87→    {
    88→        std::string  id;
    89→        double       lower_bound;   // inclusive
    90→        double       upper_bound;   // inclusive
    91→        Severity     severity;      // default severity on violation
    92→        std::string  description;
    93→    };
    94→
    95→    /* Parse configuration section “rules” into an in-memory map. */
    96→    void loadRules(const nlohmann::json& config);
    97→
    98→    /* Evaluate one numeric value against thresholds. */
    99→    std::optional<AlertMessage>
   100→    evaluate(const std::string& patient_id,
   101→             const std::string& signal_id,
   102→             double            value,
   103→             const std::string& iso_ts) const;
   104→
   105→    /* -------------------- Kafka Internals ------------------------------ */
   106→
   107→    bool initKafka(const nlohmann::json& kafkaCfg);
   108→    void processLoop(); /* Blocking loop executed on worker_ thread. */
   109→
   110→    /* Emit alert both to Kafka “alerts” topic and to in-process observers. */
   111→    void emitAlert(const AlertMessage& alert);
   112→
   113→private:
   114→    /* Kafka handles managed via smart pointers for RAII safety. */
   115→    std::unique_ptr<RdKafka::KafkaConsumer> consumer_;
   116→    std::unique_ptr<RdKafka::Producer>      producer_;
   117→
   118→    std::string                              input_topic_;
   119→    std::string                              output_topic_;
   120→
   121→    /* Domain rules: signal_id −> rule. */
   122→    std::unordered_map<std::string, ThresholdRule> rules_;
   123→
   124→    /* Concurrency primitives. */
   125→    std::vector<AlertCallback>        observers_;
   126→    mutable std::shared_mutex         observers_mtx_;
   127→
   128→    std::atomic_bool                  running_{false};
   129→    std::thread                       worker_;
   130→
   131→    /* Logger handle shared across service. */
   132→    std::shared_ptr<spdlog::logger>   log_;
   133→};
