   135→/* ======================================================================== */
   136→/*                            IMPLEMENTATION                                */
   137→/* ======================================================================== */
   138→
   139→namespace {
   140→
   141→/* Convert Severity enum to string for logging or serialization. */
   142→std::string to_string(Severity s)
   143→{
   144→    switch (s)
   145→    {
   146→    case Severity::Info:     return "INFO";
   147→    case Severity::Warning:  return "WARNING";
   148→    case Severity::Critical: return "CRITICAL";
   149→    }
   150→    return "UNKNOWN";
   151→}
   152→
   153→/* Make ISO-8601 timestamp for “now”. */
   154→std::string iso8601_now()
   155→{
   156→    using namespace std::chrono;
   157→    auto now   = system_clock::now();
   158→    auto itt   = system_clock::to_time_t(now);
   159→    auto tm    = *std::gmtime(&itt);
   160→    char buf[32];
   161→    strftime(buf, sizeof(buf), "%Y-%m-%dT%H:%M:%SZ", &tm);
   162→    return buf;
   163→}
   164→
   165→} // anonymous namespace
   166→
   167→/* -------------------- ctor / dtor --------------------------------------- */
   168→
   169→AlertingService::AlertingService(const nlohmann::json& config)
   170→{
   171→    /* Configure structured console logger (colorized). */
   172→    log_ = spdlog::stdout_color_mt("AlertingService");
   173→    log_->set_pattern("[%Y-%m-%d %H:%M:%S.%e] [%^%l%$] %v");
   174→
   175→    try
   176→    {
   177→        loadRules(config.at("rules"));
   178→        if (!initKafka(config.at("kafka")))
   179→        {
   180→            throw std::runtime_error("Failed to initialize Kafka subsystem");
   181→        }
   182→    }
   183→    catch (const std::exception& ex)
   184→    {
   185→        log_->critical("Configuration error: {}", ex.what());
   186→        throw; // propagate — service cannot run without valid config
   187→    }
   188→}
   189→
   190→AlertingService::~AlertingService()
   191→{
   192→    stop(); /* Ensure worker is stopped before destruction. */
   193→}
   194→
   195→/* -------------------- Public API ---------------------------------------- */
   196→
   197→void AlertingService::start()
   198→{
   199→    if (running_.exchange(true))
   200→    {
   201→        log_->warn("Attempt to start AlertingService while already running");
   202→        return;
   203→    }
   204→    log_->info("Starting AlertingService worker thread");
   205→    worker_ = std::thread(&AlertingService::processLoop, this);
   206→}
   207→
   208→void AlertingService::stop()
   209→{
   210→    if (!running_.exchange(false))
   211→        return; // not running
   212→
   213→    log_->info("Stopping AlertingService …");
   214→    if (worker_.joinable())
   215→        worker_.join();
   216→
   217→    if (consumer_)
   218→        consumer_->close();
   219→
   220→    /* Flush outstanding alerts before exit (up to 5 seconds). */
   221→    if (producer_)
   222→        producer_->flush(5'000);
   223→
   224→    log_->info("AlertingService cleanly stopped");
   225→}
   226→
   227→void AlertingService::registerObserver(AlertCallback cb)
   228→{
   229→    if (!cb) return;
   230→    std::unique_lock lock(observers_mtx_);
   231→    observers_.push_back(std::move(cb));
   232→}
   233→
   234→/* -------------------- Configuration Helpers ----------------------------- */
   235→
   236→void AlertingService::loadRules(const nlohmann::json& rulesCfg)
   237→{
   238→    if (!rulesCfg.is_array())
   239→        throw std::invalid_argument("config.rules must be array");
   240→
   241→    for (const auto& j : rulesCfg)
   242→    {
   243→        ThresholdRule rule;
   244→        rule.id          = j.at("id").get<std::string>();
   245→        rule.lower_bound = j.value("lower", std::numeric_limits<double>::lowest());
   246→        rule.upper_bound = j.value("upper", std::numeric_limits<double>::max());
   247→        rule.severity    = static_cast<Severity>(j.value("severity", 1)); // default Warning
   248→        rule.description = j.value("description", "");
   249→
   250→        auto signal_id   = j.at("signal_id").get<std::string>();
   251→        rules_.emplace(signal_id, std::move(rule));
   252→    }
   253→
   254→    log_->info("Loaded {} threshold rules", rules_.size());
   255→}
   256→
   257→/* -------------------- Kafka Setup --------------------------------------- */
   258→
   259→bool AlertingService::initKafka(const nlohmann::json& kafkaCfg)
   260→{
   261→    std::string brokers       = kafkaCfg.value("brokers",  "localhost:9092");
   262→    input_topic_              = kafkaCfg.value("input_topic",  "ci360.clinical.signals");
   263→    output_topic_             = kafkaCfg.value("output_topic", "ci360.alerts");
   264→
   265→    /* Consumer configuration. */
   266→    std::unique_ptr<RdKafka::Conf, std::function<void(RdKafka::Conf*)>>
   267→        conf(RdKafka::Conf::create(RdKafka::Conf::CONF_GLOBAL),
   268→             [](RdKafka::Conf* p){ delete p; });
   269→
   270→    if (!conf)
   271→    {
   272→        log_->error("Failed to allocate Kafka global config");
   273→        return false;
   274→    }
   275→
   276→    std::string errstr;
   277→    conf->set("bootstrap.servers", brokers, errstr);
   278→    conf->set("group.id",          "ci360_alerting", errstr);
   279→    conf->set("enable.auto.commit","true",           errstr);
   280→    conf->set("auto.offset.reset", "earliest",       errstr);
   281→
   282→    consumer_.reset(RdKafka::KafkaConsumer::create(conf.get(), errstr));
   283→    if (!consumer_)
   284→    {
   285→        log_->error("KafkaConsumer creation failed: {}", errstr);
   286→        return false;
   287→    }
   288→
   289→    /* Producer configuration. */
   290→    std::unique_ptr<RdKafka::Conf, std::function<void(RdKafka::Conf*)>>
   291→        prodConf(RdKafka::Conf::create(RdKafka::Conf::CONF_GLOBAL),
   292→                 [](RdKafka::Conf* p){ delete p; });
   293→
   294→    prodConf->set("bootstrap.servers", brokers, errstr);
   295→    producer_.reset(RdKafka::Producer::create(prodConf.get(), errstr));
   296→    if (!producer_)
   297→    {
   298→        log_->error("KafkaProducer creation failed: {}", errstr);
   299→        return false;
   300→    }
   301→
   302→    /* Subscribe to the input topic. */
   303→    RdKafka::ErrorCode rc = consumer_->subscribe({input_topic_});
   304→    if (rc != RdKafka::ERR_NO_ERROR)
   305→    {
   306→        log_->error("Failed to subscribe to {}: {}", input_topic_, RdKafka::err2str(rc));
   307→        return false;
   308→    }
   309→
   310→    log_->info("Kafka initialized: listening on '{}', producing to '{}'", input_topic_, output_topic_);
   311→    return true;
   312→}
   313→
   314→/* -------------------- Processing Loop ----------------------------------- */
   315→
   316→void AlertingService::processLoop()
   317→{
   318→    const int POLL_TIMEOUT_MS = 500;
   319→
   320→    while (running_)
   321→    {
   322→        std::unique_ptr<RdKafka::Message, std::function<void(RdKafka::Message*)>>
   323→            msg(consumer_->consume(POLL_TIMEOUT_MS), [](RdKafka::Message* m){ delete m; });
   324→
   325→        if (!msg) continue;
   326→
   327→        switch (msg->err())
   328→        {
   329→        case RdKafka::ERR_NO_ERROR:
   330→        {
   331→            /* Parse JSON payload. Example message:
   332→             * { "patient_id":"1234",
   333→             *   "signal_id":"ECG_HR",
   334→             *   "value":95.0,
   335→             *   "ts":"2024-03-05T10:35:00Z" }
   336→             */
   337→            try
   338→            {
   339→                nlohmann::json payload = nlohmann::json::parse(
   340→                    static_cast<const char*>(msg->payload()),
   341→                    static_cast<const char*>(msg->payload()) + msg->len());
   342→
   343→                std::string patient_id = payload.at("patient_id").get<std::string>();
   344→                std::string signal_id  = payload.at("signal_id").get<std::string>();
   345→                double      value      = payload.at("value").get<double>();
   346→                std::string ts         = payload.value("ts", iso8601_now());
   347→
   348→                if (auto alertOpt = evaluate(patient_id, signal_id, value, ts))
   349→                {
   350→                    emitAlert(*alertOpt);
   351→                }
   352→            }
   353→            catch (const std::exception& ex)
   354→            {
   355→                log_->error("Failed to process message: {}", ex.what());
   356→            }
   357→            break;
   358→        }
   359→        case RdKafka::ERR__TIMED_OUT:
   360→            /* Normal — no message within timeout. */
   361→            break;
   362→        default:
   363→            log_->warn("Kafka consume error: {}", msg->errstr());
   364→            break;
   365→        }
   366→    }
   367→}
   368→
   369→/* -------------------- Rule Evaluation ----------------------------------- */
   370→
   371→std::optional<AlertMessage>
   372→AlertingService::evaluate(const std::string& patient_id,
   373→                          const std::string& signal_id,
   374→                          double            value,
   375→                          const std::string& iso_ts) const
   376→{
   377→    auto it = rules_.find(signal_id);
   378→    if (it == rules_.end())
   379→        return std::nullopt; // No rule for this signal
   380→
   381→    const ThresholdRule& rule = it->second;
   382→    if (value < rule.lower_bound || value > rule.upper_bound)
   383→    {
   384→        AlertMessage alert;
   385→        alert.patient_id  = patient_id;
   386→        alert.rule_id     = rule.id;
   387→        alert.severity    = rule.severity;
   388→        alert.description = rule.description.empty()
   389→                                ? "Threshold violation on " + signal_id
   390→                                : rule.description;
   391→        alert.timestamp_utc = iso_ts;
   392→        return alert;
   393→    }
   394→    return std::nullopt;
   395→}
   396→
   397→/* -------------------- Alert Propagation --------------------------------- */
   398→
   399→void AlertingService::emitAlert(const AlertMessage& alert)
   400→{
   401→    /* Serialize to JSON for Kafka. */
   402→    nlohmann::json j{
   403→        {"patient_id", alert.patient_id},
   404→        {"rule_id",    alert.rule_id},
   405→        {"severity",   to_string(alert.severity)},
   406→        {"description",alert.description},
   407→        {"ts",         alert.timestamp_utc}
   408→    };
   409→
   410→    std::string payload = j.dump();
   411→
   412→    RdKafka::ErrorCode rc = producer_->produce(
   413→        output_topic_, RdKafka::Topic::PARTITION_UA,
   414→        RdKafka::Producer::RK_MSG_COPY /* Copy payload */,
   415→        const_cast<char*>(payload.data()), payload.size(),
   416→        nullptr, 0, 0, nullptr);
   417→
   418→    if (rc != RdKafka::ERR_NO_ERROR)
   419→    {
   420→        log_->error("Failed to enqueue alert for patient {}: {}",
   421→                    alert.patient_id, RdKafka::err2str(rc));
   422→    }
   423→    else
   424→    {
   425→        log_->info("Alert emitted for patient {} (severity {})",
   426→                   alert.patient_id, to_string(alert.severity));
   427→    }
   428→
   429→    /* Flush producer queue in background thread. */
   430→    producer_->poll(0);
   431→
   432→    /* Notify in-process observers. */
   433→    std::shared_lock lock(observers_mtx_);
   434→    for (const auto& cb : observers_)
   435→    {
   436→        try
   437→        {
