    46→class ScheduledTask
    47→{
    48→public:
    49→    ScheduledTask(std::string               id,
    50→                  std::string               name,
    51→                  std::chrono::milliseconds period,
    52→                  ExecutionMode             mode,
    53→                  std::function<void()>     fn)
    54→        : _id{std::move(id)}
    55→        , _name{std::move(name)}
    56→        , _period{period}
    57→        , _mode{mode}
    58→        , _fn{std::move(fn)}
    59→        , _nextFire{Clock::now() + _period}
    60→    {
    61→    }
    62→
    63→    using Clock      = std::chrono::steady_clock;
    64→    using TimePoint  = Clock::time_point;
    65→
    66→    const std::string& id() const noexcept { return _id; }
    67→    const std::string& name() const noexcept { return _name; }
    68→    std::chrono::milliseconds period() const noexcept { return _period; }
    69→    ExecutionMode mode() const noexcept { return _mode; }
    70→    TimePoint nextFire() const noexcept { return _nextFire; }
    71→
    72→    void dispatch(tbb::task_group& tg)
    73→    {
    74→        auto start_time = Clock::now();
    75→
    76→        tg.run([this, start_time]() {
    77→            try
    78→            {
    79→                _fn();
    80→                metrics::incrementCounter("scheduler.task.success", {{"task", _name}});
    81→            }
    82→            catch (const std::exception& ex)
    83→            {
    84→                spdlog::error("Scheduled task '{}' failed: {}", _name, ex.what());
    85→                metrics::incrementCounter("scheduler.task.failure", {{"task", _name}});
    86→
    87→                // propagate to system-wide event bus for central error handling
    88→                core::EventBus::instance().publish("internal.error",
    89→                                                   {{"task", _name}, {"error", ex.what()}});
    90→            }
    91→        });
    92→
    93→        // compute nextFire according to execution mode
    94→        if (_mode == ExecutionMode::FixedRate)
    95→        {
    96→            _nextFire += _period; // relative to original start
    97→        }
    98→        else
    99→        {
   100→            auto completion_time = Clock::now();
   101→            _nextFire            = completion_time + _period; // relative to completion
   102→        }
   103→    }
   104→
   105→    bool operator>(const ScheduledTask& other) const noexcept
   106→    {
   107→        return _nextFire > other._nextFire;
   108→    }
   109→
   110→private:
   111→    std::string               _id;
   112→    std::string               _name;
   113→    std::chrono::milliseconds _period;
   114→    ExecutionMode             _mode;
   115→    std::function<void()>     _fn;
   116→    TimePoint                 _nextFire;
