   378→        observers_.push_back(std::move(obs));
   379→    }
   380→
   381→    void start()
   382→    {
   383→        if (running_.exchange(true))
   384→            return; // already running
   385→
   386→        worker_ = std::thread([self = shared_from_this()] { self->runLoop(); });
   387→    }
   388→
   389→    void stop()
   390→    {
   391→        if (!running_.exchange(false))
   392→            return;
   393→
   394→        if (worker_.joinable()) worker_.join();
   395→    }
   396→
   397→private:
   398→    void runLoop()
   399→    {
   400→        tbb::flow::graph g;
   401→
   402→        using Batch = std::vector<PatientDataRecord>;
   403→
   404→        tbb::flow::function_node<Batch> transformNode(
   405→            g,
   406→            cfg_.transformer_concurrency,
   407→            [this](Batch batch) {
   408→                transformer_->transform(batch);
   409→                std::string reason;
   410→                if (!validator_->validate(batch, reason))
   411→                {
   412→                    metrics_.batches_failed++;
   413→                    notify();
   414→                    return; // drop invalid batch
   415→                }
   416→                loader_->load(batch);
   417→                metrics_.records_processed += batch.size();
   418→                metrics_.batches_success++;
   419→                notify();
   420→            });
   421→
   422→        while (running_)
   423→        {
   424→            Batch batch;
   425→            if (!extractor_->extract(batch))
   426→            {
   427→                // End-of-stream: drain graph then break
   428→                running_ = false;
   429→                break;
   430→            }
   431→            transformNode.try_put(std::move(batch));
   432→        }
   433→
   434→        g.wait_for_all();
   435→    }
   436→
   437→    void notify()
   438→    {
   439→        std::lock_guard<std::mutex> lg(obsMtx_);
