   441→        {
   442→            if (auto obs = it->lock())
   443→            {
   444→                obs->onMetrics(metrics_);
   445→                ++it;
   446→            }
   447→            else
   448→            {
   449→                it = observers_.erase(it); // remove expired
   450→            }
   451→        }
   452→    }
