    74→/**
    75→ * A very small RAII wrapper around OpenSSL’s EVP_CIPHER_CTX.
    76→ */
    77→class EvpCipherCtx final
    78→{
    79→public:
    80→    EvpCipherCtx()
    81→        : ctx_{ EVP_CIPHER_CTX_new() }
    82→    {
    83→        if (!ctx_) { throw std::runtime_error("EVP_CIPHER_CTX_new failed"); }
    84→    }
    85→    ~EvpCipherCtx() { EVP_CIPHER_CTX_free(ctx_); }
    86→    EVP_CIPHER_CTX* get() noexcept { return ctx_; }
    87→
    88→    EvpCipherCtx(const EvpCipherCtx&)            = delete;
    89→    EvpCipherCtx& operator=(const EvpCipherCtx&) = delete;
    90→
    91→private:
    92→    EVP_CIPHER_CTX* ctx_;
    93→};
