   146→/**
   147→ * Decrypts buffer produced by `aes256_gcm_encrypt`.
   148→ */
   149→void aes256_gcm_decrypt(const std::vector<std::uint8_t>& src,
   150→                        const std::array<std::uint8_t, 32>& key,
   151→                        std::vector<std::uint8_t>&        dst)
   152→{
   153→    if (src.size() < kAesIvBytes + kAesTagBytes)
   154→        throw std::runtime_error("ciphertext too small");
   155→
   156→    const std::uint8_t* iv    = src.data();
   157→    const std::uint8_t* tag   = src.data() + kAesIvBytes;
   158→    const std::uint8_t* ctext = src.data() + kAesIvBytes + kAesTagBytes;
   159→    const auto          c_len = static_cast<int>(src.size() - kAesIvBytes - kAesTagBytes);
   160→
   161→    const EVP_CIPHER* alg = EVP_aes_256_gcm();
   162→    EvpCipherCtx      ctx;
   163→    if (EVP_DecryptInit_ex(ctx.get(), alg, nullptr, nullptr, nullptr) != 1)
   164→        throw std::runtime_error("EVP_DecryptInit_ex failed");
   165→
   166→    if (EVP_CIPHER_CTX_ctrl(ctx.get(), EVP_CTRL_GCM_SET_IVLEN, kAesIvBytes, nullptr) != 1)
   167→        throw std::runtime_error("EVP_CIPHER_CTX_ctrl failed (set iv len)");
   168→
   169→    if (EVP_DecryptInit_ex(ctx.get(), nullptr, nullptr, key.data(), iv) != 1)
   170→        throw std::runtime_error("EVP_DecryptInit_ex failed (key/iv)");
   171→
   172→    dst.resize(c_len + EVP_CIPHER_block_size(alg)); // alloc
   173→    int out_len = 0;
   174→    if (EVP_DecryptUpdate(ctx.get(), dst.data(), &out_len, ctext, c_len) != 1)
   175→        throw std::runtime_error("EVP_DecryptUpdate failed");
   176→
   177→    if (EVP_CIPHER_CTX_ctrl(ctx.get(), EVP_CTRL_GCM_SET_TAG, kAesTagBytes,
   178→                            const_cast<std::uint8_t*>(tag)) != 1)
   179→        throw std::runtime_error("EVP_Decrypt ctrl (set tag) failed");
   180→
   181→    int tmp_len = 0;
   182→    if (EVP_DecryptFinal_ex(ctx.get(), dst.data() + out_len, &tmp_len) != 1)
   183→        throw std::runtime_error("EVP_DecryptFinal_ex authentication failed");
   184→
   185→    out_len += tmp_len;
   186→    dst.resize(out_len);
   187→}
