   189→/**
   190→ * Formats a std::chrono::system_clock::time_point into YYYY/MM/DD/HHMMSS.
   191→ */
   192→inline std::string to_iso_path(const std::chrono::system_clock::time_point& tp)
   193→{
   194→    std::time_t          tt = std::chrono::system_clock::to_time_t(tp);
   195→    std::tm              tm{};
   196→#if defined(_WIN32)
   197→    gmtime_s(&tm, &tt);
   198→#else
   199→    gmtime_r(&tt, &tm);
   200→#endif
   201→    std::ostringstream oss;
   202→    oss << std::put_time(&tm, "%Y/%m/%d/%H%M%S");
   203→    return oss.str();
   204→}
   205→
   206→/**
   207→ * Formats a time_point to ISO-8601 basic: YYYYMMDDThhmmssZ
   208→ */
   209→inline std::string to_iso_basic(const std::chrono::system_clock::time_point& tp)
   210→{
   211→    std::time_t          tt = std::chrono::system_clock::to_time_t(tp);
   212→    std::tm              tm{};
   213→#if defined(_WIN32)
   214→    gmtime_s(&tm, &tt);
   215→#else
   216→    gmtime_r(&tt, &tm);
   217→#endif
   218→    std::ostringstream oss;
   219→    oss << std::put_time(&tm, "%Y%m%dT%H%M%SZ");
   220→    return oss.str();
   221→}
