   229→DataLakeFacade::DataLakeFacade(DataLakeOptions opts)
   230→    : opts_{ std::move(opts) }
   231→    , arena_{ static_cast<int>(opts_.concurrency) } // limit concurrency
   232→{
   233→    if (!fs::exists(opts_.root_directory))
   234→    {
   235→        fs::create_directories(opts_.root_directory);
   236→    }
   237→
   238→    if (opts_.encryption_enabled)
