   249→
   250→void DataLakeFacade::write_raw(const std::shared_ptr<arrow::Table>&            table,
   251→                               std::string_view                                signal_type,
   252→                               std::string_view                                patient_id,
   253→                               const std::chrono::system_clock::time_point&    capture_time) const
   254→{
   255→    if (!table) throw std::invalid_argument("table is null");
   256→
   257→    const fs::path base =
   258→        opts_.root_directory / "raw" / signal_type / patient_id / to_iso_path(capture_time);
   259→
   260→    fs::create_directories(base);
   261→
   262→    // Split table into chunks so we can write multiple parquet files in parallel.
   263→    const std::size_t total_rows = table->num_rows();
   264→    const std::size_t rows_per_chunk =
   265→        std::max<std::size_t>(kDefaultChunkRows, total_rows / arena_.max_concurrency());
   266→
   267→    std::size_t chunks = (total_rows + rows_per_chunk - 1) / rows_per_chunk;
   268→
   269→    arena_.execute([&] {
   270→        tbb::parallel_for(std::size_t{ 0 }, chunks, [&](std::size_t chunk_idx) {
   271→            const std::size_t offset = chunk_idx * rows_per_chunk;
   272→            const std::size_t length =
   273→                std::min<std::size_t>(rows_per_chunk, total_rows - offset);
   274→
   275→            auto slice = table->Slice(offset, length);
   276→
   277→            std::ostringstream fname;
   278→            fname << "part_" << std::setfill('0') << std::setw(4) << chunk_idx << ".parquet";
   279→
   280→            const fs::path file_path = base / fname.str();
   281→            write_table_to_file(slice, file_path);
   282→        });
   283→    });
   284→}
