   298→std::vector<fs::path> DataLakeFacade::list_datasets(const fs::path& subdir) const
   299→{
   300→    const fs::path dir = opts_.root_directory / subdir;
   301→    if (!fs::exists(dir)) return {};
   302→
   303→    std::vector<fs::path> result;
   304→    for (auto& p : fs::recursive_directory_iterator(dir))
   305→    {
   306→        if (p.is_regular_file() && p.path().extension() == ".parquet")
   307→        {
   308→            result.emplace_back(p.path());
   309→        }
   310→    }
   311→    return result;
   312→}
