   314→arrow::Result<std::shared_ptr<arrow::Table>>
   315→DataLakeFacade::read_dataset(const fs::path& file_path) const
   316→{
   317→    ARROW_ASSIGN_OR_RAISE(auto input_file, arrow::io::ReadableFile::Open(file_path.string()));
   318→
   319→    if (opts_.encryption_enabled)
   320→    {
   321→        // Whole-file encryption – read into memory, decrypt, then open from buffer.
   322→        ARROW_ASSIGN_OR_RAISE(auto buf, input_file->Read());
   323→        std::vector<std::uint8_t> cipher(buf->size());
   324→        std::memcpy(cipher.data(), buf->data(), buf->size());
   325→
   326→        std::vector<std::uint8_t> plain;
   327→        aes256_gcm_decrypt(cipher, encryption_key_, plain);
   328→
   329→        auto plain_buf = std::make_shared<arrow::Buffer>(plain.data(), plain.size());
   330→        auto stream    = std::make_shared<arrow::io::BufferReader>(plain_buf);
   331→        return parquet::arrow::ReadTable(stream);
   332→    }
   333→    else
   334→    {
   335→        std::unique_ptr<parquet::arrow::FileReader> reader;
   336→        PARQUET_THROW_NOT_OK(
   337→            parquet::arrow::OpenFile(input_file, arrow::default_memory_pool(), &reader));
   338→
   339→        std::shared_ptr<arrow::Table> table;
   340→        PARQUET_THROW_NOT_OK(reader->ReadTable(&table));
   341→        return table;
   342→    }
   343→}
