   161→void ConfigManager::overlayEnvironmentVariables(json& cfg) const
   162→{
   163→    /* Environment override syntax:
   164→     *   CI360_CFG_<UPPERCASE_WITH_UNDERSCORES>=value
   165→     * It maps to JSON keys using '.' as separator.
   166→     *
   167→     * Example:
   168→     *   CI360_CFG_STREAMING_KAFKA.BOOTSTRAP_SERVERS=localhost:9092
   169→     *   -> json["streaming"]["kafka"]["bootstrap_servers"]
   170→     */
   171→    constexpr std::string_view prefix = "CI360_CFG_";
   172→
   173→#if defined(_WIN32)
   174→    // Windows: use getenv_s
   175→    size_t  len = 0;
   176→    char**  envVars = nullptr;
   177→    _dupenv_s(envVars, &len, "*"); // Ugly: retrieving entire env on Windows is non-portable.
   178→#else
   179→    extern char** environ; // POSIX
   180→    for (char** env = environ; *env != nullptr; ++env) {
   181→        std::string var{ *env };
   182→        if (var.rfind(prefix, 0) != 0) continue; // skip non-prefixed
   183→        auto eqPos = var.find('=');
   184→        if (eqPos == std::string::npos) continue;
   185→
   186→        std::string key = var.substr(prefix.size(), eqPos - prefix.size());
   187→        std::string val = var.substr(eqPos + 1);
   188→
   189→        // Normalize: UPPERCASE_WITH_UNDERSCORES -> lowercase.with.dots
   190→        utils::strings::toLower(key);
   191→        std::replace(key.begin(), key.end(), '_', '.');
   192→
   193→        // Drill/create hierarchy
   194→        json* cursor = &cfg;
   195→        auto  tokens = utils::strings::split(key, '.');
   196→        for (size_t i = 0; i < tokens.size(); ++i) {
   197→            const auto& tk = tokens[i];
   198→            if (i + 1 == tokens.size()) {
   199→                // leaf
   200→                (*cursor)[tk] = val;
   201→            } else {
   202→                cursor = &((*cursor)[tk]);
   203→            }
   204→        }
   205→        _logger->debug("Environment override: {} -> {}", key, val);
   206→    }
   207→#endif
   208→}
