   210→void ConfigManager::startWatcherThread()
   211→{
   212→    _watcherThread = std::thread([this] {
   213→        auto lastWriteTime = std::filesystem::last_write_time(_configPath);
   214→        while (!_terminateWatcher.test()) {
   215→            std::this_thread::sleep_for(_pollInterval);
   216→
   217→            std::error_code ec;
   218→            auto currentWriteTime = std::filesystem::last_write_time(_configPath, ec);
   219→            if (ec) {
   220→                _logger->warn("Unable to stat config file: {}", ec.message());
   221→                continue;
   222→            }
   223→
   224→            if (currentWriteTime != lastWriteTime) {
   225→                _logger->info("Detected change in configuration file");
   226→                lastWriteTime = currentWriteTime;
   227→                reload();
   228→            }
   229→        }
   230→    });
   231→    _logger->info("Started configuration file watcher thread");
   232→}
   233→
   234→void ConfigManager::notifyCallbacks()
   235→{
   236→    std::vector<CallbackFn> snapshot;
   237→    {
   238→        std::unique_lock lock{ _callbackMutex };
   239→        snapshot = _callbacks; // copy
   240→    }
   241→
   242→    for (auto& cb : snapshot) {
   243→        try {
   244→            cb();
   245→        } catch (const std::exception& ex) {
   246→            _logger->error("Exception thrown from ConfigManager callback: {}", ex.what());
   247→        }
   248→    }
   249→}
