   251→/**
   252→ * Helper: navigate nested JSON using dotted keys.
   253→ * Returns nullptr if key is not present.
   254→ */
   255→const json* ConfigManager::drillDown(const json& root, std::string_view dotted) const
   256→{
   257→    size_t pos   = 0;
   258→    size_t start = 0;
   259→    const json* node = &root;
   260→
   261→    while (pos != std::string_view::npos) {
   262→        pos = dotted.find('.', start);
   263→        std::string_view token = dotted.substr(start, pos == std::string_view::npos
   264→                                                     ? std::string_view::npos
   265→                                                     : pos - start);
   266→
   267→        if (!node->contains(token)) {
   268→            return nullptr;
   269→        }
   270→        node = &((*node)[token]);
   271→        start = pos + 1;
   272→    }
   273→    return node;
   274→}
